//! # Adaptive conformal layer early-exit (DEFAULT OFF).
//!
//! Skip transformer layers per token whenever the certified `2·τ ≤ γ` energy
//! gate guarantees the greedy argmax cannot change. This is axis-1 of
//! `../distributed-inference-host/docs/speculative-decoding-plan.md`: a
//! training-free, codebase-native depth shortcut for one token, governed by the
//! conformal certificate (`crate::conformal_gate`). There is NO draft/verify
//! loop and NO KV rollback — the certificate replaces verification.
//!
//! Re-pointing of the gate (vs. the quant-tile meaning it has elsewhere):
//!
//! | gate input | early-exit meaning |
//! |---|---|
//! | `τ`   | sup-norm residual: early-exit-`k` logits vs full-depth logits |
//! | `γ`   | top1 − top2 logit margin at this step |
//! | config| `(model, exit-layer-k)` |
//! | admit | exit the transformer at layer `k`, finalize with its logits |
//!
//! ## Cost model (why we only probe a FEW layers)
//!
//! Computing γ at a candidate layer requires a full `lm_head` matmul (≈ a few
//! layers of work). So we check the gate at only a handful of candidate exit
//! layers placed in the back half, not every layer. Net win iff
//! `(layers_saved) > (extra lm_heads paid on non-admitted checks)`. When a probe
//! is admitted, its logits ARE the output (no waste).

#![allow(dead_code)]

use crate::conformal_gate::{conformal_admit, ResidualCalibration};

/// Read the `GNOSIS_EARLY_EXIT` flag. Enabled only when set to
/// `1`/`true`/`on`/`yes`. Mirrors `crate::tau_bowl_dequant::enabled()` so the
/// hot path is never perturbed when off.
#[inline]
pub fn enabled() -> bool {
    match std::env::var("GNOSIS_EARLY_EXIT") {
        Ok(v) => {
            let v = v.trim().to_ascii_lowercase();
            v == "1" || v == "true" || v == "on" || v == "yes"
        }
        Err(_) => false,
    }
}

/// Coverage `q` for the conformal certificate (flip-rate budget `1 − q`).
/// Override with `GNOSIS_EARLY_EXIT_Q` (default 0.99 ⇒ ≤1% certified flips).
pub fn coverage_q() -> f64 {
    std::env::var("GNOSIS_EARLY_EXIT_Q")
        .ok()
        .and_then(|v| v.trim().parse::<f64>().ok())
        .filter(|q| *q > 0.0 && *q < 1.0)
        .unwrap_or(0.99)
}

/// LOSSY saturation early-exit threshold ε (DEFAULT OFF). When set (> 0) via
/// `GNOSIS_EARLY_EXIT_EPSILON`, `forward_one` exits at the first layer
/// `l >= min_exit_layer` whose relative residual delta
/// `‖h_{l-1} − h_{l-2}‖₂ / ‖h_{l-1}‖₂ < ε`. This is a CHEAP `O(hidden_dim)`
/// norm — no `lm_head` probe — so it can be checked at every layer. Larger ε ⇒
/// exits earlier ⇒ faster but lower agreement (the flip-rate knob). Returns
/// `None` when unset/non-positive so the saturation gate stays off by default.
pub fn saturation_epsilon() -> Option<f64> {
    std::env::var("GNOSIS_EARLY_EXIT_EPSILON")
        .ok()
        .and_then(|v| v.trim().parse::<f64>().ok())
        .filter(|e| e.is_finite() && *e > 0.0)
}

/// Earliest layer index a saturation/margin exit may fire at. Below this depth
/// the gate is never consulted (the network has not had a chance to converge).
/// Override with `GNOSIS_EARLY_EXIT_MIN_LAYER` (default: half the depth).
pub fn min_exit_layer_for(num_layers: usize) -> usize {
    std::env::var("GNOSIS_EARLY_EXIT_MIN_LAYER")
        .ok()
        .and_then(|v| v.trim().parse::<usize>().ok())
        .filter(|&m| m < num_layers)
        .unwrap_or(num_layers / 2)
}

/// LOSSY margin gate threshold θ (DEFAULT OFF). When set via
/// `GNOSIS_EARLY_EXIT_THETA`, a candidate-layer `lm_head` probe admits whenever
/// `top2_margin ≥ θ`, DECOUPLED from the conformal `2·τ` bound. Free knob for
/// the speed/quality sweep. Returns `None` when unset (use the conformal gate).
pub fn margin_theta() -> Option<f64> {
    std::env::var("GNOSIS_EARLY_EXIT_THETA")
        .ok()
        .and_then(|v| v.trim().parse::<f64>().ok())
        .filter(|t| t.is_finite() && *t >= 0.0)
}

/// Relative L2 residual-saturation metric: `‖curr − prev‖₂ / ‖curr‖₂`.
/// This is the cheap per-layer convergence probe for the lossy saturation gate.
/// Returns `f64::INFINITY` when `curr` has ~zero norm (never saturate-exit on a
/// degenerate residual) and `0.0` when the two are bit-identical.
#[inline]
pub fn relative_l2_delta(curr: &[f32], prev: &[f32]) -> f64 {
    debug_assert_eq!(curr.len(), prev.len());
    let mut diff_sq = 0.0f64;
    let mut curr_sq = 0.0f64;
    for (c, p) in curr.iter().zip(prev.iter()) {
        let c = *c as f64;
        let d = c - *p as f64;
        diff_sq += d * d;
        curr_sq += c * c;
    }
    if curr_sq <= f64::MIN_POSITIVE {
        return f64::INFINITY;
    }
    (diff_sq / curr_sq).sqrt()
}

/// Per-layer sup-norm residual calibration + the runtime config for adaptive
/// early-exit. Built offline (or on the prompt's own prefill) by recording, at
/// each candidate exit layer, the sup-norm residual between the early-exit
/// logits and the full-depth logits over a calibration token set.
#[derive(Clone, Debug)]
pub struct EarlyExitConfig {
    /// Candidate exit layers (ascending), each in `[1, num_layers)`. A token
    /// finalizes at the FIRST of these whose `2·Q_q ≤ γ`.
    pub candidate_layers: Vec<usize>,
    /// Conformal calibration of the sup-norm residual, one per candidate layer
    /// (same index order as `candidate_layers`). Empty until calibrated.
    pub calibrations: Vec<ResidualCalibration>,
    /// Coverage used to build / admit (`1 − q` = certified flip-rate budget).
    pub q: f64,
}

impl EarlyExitConfig {
    /// Default candidate set: a few layers in the back half of the network.
    /// Override with `GNOSIS_EARLY_EXIT_LAYERS=20,24,28` (comma-separated).
    pub fn candidates_from_env(num_layers: usize) -> Vec<usize> {
        if let Ok(raw) = std::env::var("GNOSIS_EARLY_EXIT_LAYERS") {
            let mut v: Vec<usize> = raw
                .split(',')
                .filter_map(|s| s.trim().parse::<usize>().ok())
                .filter(|&k| k >= 1 && k < num_layers)
                .collect();
            v.sort_unstable();
            v.dedup();
            if !v.is_empty() {
                return v;
            }
        }
        // Default: 3 probes at ~ 5/8, 6/8, 7/8 of depth (back half).
        let mut v: Vec<usize> = [5, 6, 7]
            .iter()
            .map(|&n| (num_layers * n) / 8)
            .filter(|&k| k >= 1 && k < num_layers)
            .collect();
        v.sort_unstable();
        v.dedup();
        v
    }

    /// Fresh, uncalibrated config from the environment.
    pub fn from_env(num_layers: usize) -> Self {
        let candidate_layers = Self::candidates_from_env(num_layers);
        let n = candidate_layers.len();
        Self {
            candidate_layers,
            calibrations: Vec::with_capacity(n),
            q: coverage_q(),
        }
    }

    /// Per-candidate-layer `(layer, conformal τ_q, calibration_n)` — diagnostic
    /// for the bench so the admit/miss behavior is explainable (admit iff a
    /// token's margin γ ≥ 2·τ_q at some candidate).
    pub fn calibration_report(&self) -> Vec<(usize, f64, usize)> {
        self.candidate_layers
            .iter()
            .enumerate()
            .map(|(i, &layer)| {
                let (tq, n) = self
                    .calibrations
                    .get(i)
                    .map(|c| (c.conformal_quantile(self.q), c.len()))
                    .unwrap_or((f64::INFINITY, 0));
                (layer, tq, n)
            })
            .collect()
    }

    pub fn is_calibrated(&self) -> bool {
        !self.calibrations.is_empty() && self.calibrations.len() == self.candidate_layers.len()
    }

    /// Admit candidate index `i` at margin `gamma` (the margin of THAT layer's
    /// own exit logits). `2·Q_q(i) ≤ γ` is the proven energy bound
    /// (`conformal_admit`). Each candidate is judged against its OWN per-layer
    /// calibration and its OWN margin — this is the per-layer decision the
    /// `forward_one` probe makes as it walks candidates shallow→deep.
    pub fn admit_index(&self, i: usize, gamma: f64) -> bool {
        if !self.is_calibrated() || i >= self.calibrations.len() {
            return false;
        }
        conformal_admit(&self.calibrations[i], self.q, gamma).admissible
    }

    /// The earliest candidate layer admitted at a SINGLE shared margin `gamma`,
    /// with its index into `candidate_layers`. Used by unit tests and any caller
    /// that holds one margin; the live `forward_one` probe instead uses
    /// [`Self::admit_index`] because γ is re-measured at each candidate depth.
    /// `2·Q_q ≤ γ` is the proven energy bound (`conformal_admit`).
    pub fn admit_layer(&self, gamma: f64) -> Option<(usize, usize)> {
        if !self.is_calibrated() {
            return None;
        }
        for (i, &layer) in self.candidate_layers.iter().enumerate() {
            if self.admit_index(i, gamma) {
                return Some((i, layer));
            }
        }
        None
    }
}

/// Sup-norm (L∞) distance between two logit vectors of equal length.
#[inline]
pub fn sup_norm_residual(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    let mut m = 0.0f64;
    for (x, y) in a.iter().zip(b.iter()) {
        let d = (*x as f64 - *y as f64).abs();
        if d > m {
            m = d;
        }
    }
    m
}

/// Top1 − top2 margin γ over a logit vector (the decision margin). Returns 0.0
/// if there are fewer than 2 entries.
#[inline]
pub fn top2_margin(logits: &[f32]) -> f64 {
    let mut best = f32::NEG_INFINITY;
    let mut second = f32::NEG_INFINITY;
    for &v in logits {
        if v > best {
            second = best;
            best = v;
        } else if v > second {
            second = v;
        }
    }
    if !second.is_finite() {
        return 0.0;
    }
    (best - second).max(0.0) as f64
}

/// argmax over a logit vector.
#[inline]
pub fn argmax(logits: &[f32]) -> usize {
    let mut best = 0usize;
    let mut best_val = f32::NEG_INFINITY;
    for (i, &v) in logits.iter().enumerate() {
        if v > best_val {
            best = i;
            best_val = v;
        }
    }
    best
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn sup_norm_and_margin_basic() {
        let a = [1.0f32, 2.0, 5.0, 0.0];
        let b = [1.0f32, 2.5, 4.0, 0.0];
        assert!((sup_norm_residual(&a, &b) - 1.0).abs() < 1e-9);
        // top1=5, top2=2 ⇒ margin 3
        assert!((top2_margin(&a) - 3.0).abs() < 1e-9);
        assert_eq!(argmax(&a), 2);
    }

    #[test]
    fn admit_requires_calibration() {
        let cfg = EarlyExitConfig {
            candidate_layers: vec![10, 14],
            calibrations: vec![],
            q: 0.99,
        };
        assert!(cfg.admit_layer(100.0).is_none(), "uncalibrated must never admit");
    }

    #[test]
    fn admit_picks_earliest_layer_clearing_the_bound() {
        // Layer 10: residual ~0.5 (Q_0.9 ~0.5 ⇒ needs γ ≥ ~1.0)
        // Layer 14: residual ~0.1 (Q_0.9 ~0.1 ⇒ needs γ ≥ ~0.2)
        let cal_shallow = ResidualCalibration::from_residuals(&vec![0.5; 200]);
        let cal_deep = ResidualCalibration::from_residuals(&vec![0.1; 200]);
        let cfg = EarlyExitConfig {
            candidate_layers: vec![10, 14],
            calibrations: vec![cal_shallow, cal_deep],
            q: 0.90,
        };
        // Small margin: only the deep (tight) layer clears.
        let (idx, layer) = cfg.admit_layer(0.25).expect("deep layer should admit");
        assert_eq!((idx, layer), (1, 14));
        // Large margin: the earliest (shallow) layer clears ⇒ bigger savings.
        let (idx2, layer2) = cfg.admit_layer(1.5).expect("shallow should admit at big margin");
        assert_eq!((idx2, layer2), (0, 10));
        // Tiny margin: nothing clears ⇒ full depth.
        assert!(cfg.admit_layer(0.05).is_none());
    }

    #[test]
    fn relative_l2_delta_basic() {
        // Identical vectors ⇒ 0 saturation (fully converged).
        let v = [3.0f32, 4.0, 0.0];
        assert!(relative_l2_delta(&v, &v).abs() < 1e-12);
        // curr = [3,4] (‖·‖=5), prev=[0,0] ⇒ delta=5, rel = 5/5 = 1.0.
        let curr = [3.0f32, 4.0];
        let prev = [0.0f32, 0.0];
        assert!((relative_l2_delta(&curr, &prev) - 1.0).abs() < 1e-9);
        // Small perturbation ⇒ small relative delta (the saturation regime).
        let a = [10.0f32, 0.0, 0.0];
        let b = [10.0f32, 0.1, 0.0]; // ‖diff‖=0.1, ‖a... use curr=b
        // rel vs curr=b: ‖b−a‖=0.1, ‖b‖≈10.0005 ⇒ ~0.01
        let r = relative_l2_delta(&b, &a);
        assert!(r > 0.0 && r < 0.02, "expected small saturation, got {r}");
    }

    #[test]
    fn relative_l2_delta_degenerate_curr_is_infinite() {
        // Zero curr ⇒ never saturate-exit (guard against div-by-zero noise).
        let curr = [0.0f32, 0.0, 0.0];
        let prev = [1.0f32, 2.0, 3.0];
        assert!(relative_l2_delta(&curr, &prev).is_infinite());
    }

    #[test]
    fn saturation_gate_fires_below_epsilon() {
        // Simulate the gate decision: exit iff rel_delta < ε at l >= min_layer.
        let eps = 0.05f64;
        let h_prev = [1.0f32, 2.0, 3.0, 4.0];
        // Nearly-converged next residual (tiny change) ⇒ below ε ⇒ exit.
        let h_conv = [1.001f32, 2.001, 3.001, 4.001];
        assert!(relative_l2_delta(&h_conv, &h_prev) < eps);
        // Still-moving residual ⇒ above ε ⇒ keep running.
        let h_moving = [1.5f32, 2.5, 3.5, 4.5];
        assert!(relative_l2_delta(&h_moving, &h_prev) >= eps);
    }

    #[test]
    fn default_candidates_are_in_back_half_and_in_range() {
        let c = EarlyExitConfig::candidates_from_env(32);
        for &k in &c {
            assert!(k >= 16 && k < 32, "candidate {k} should be back-half of 32");
        }
        assert!(!c.is_empty());
    }
}
